def jazz_era_orchestras(db):
    orchestras = db.query("SELECT * FROM orchestras WHERE era='early 20th century' AND genre='jazz'")
    for orchestra in orchestras:
        print(f"Orchestra: {orchestra.name}, Founded: {orchestra.founded}, Conductor: {orchestra.conductor}")
        musicians = db.query(f"SELECT * FROM musicians WHERE orchestra_id={orchestra.id}")
        for musician in musicians:
            print(f"  Musician: {musician.name}, Instrument: {musician.instrument}")
    return orchestras
